export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  // Count neighbors for a specific cell
  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
          count++;
        }
      }
    }
    return count;
  };

  // Collect all candidate cells (live cells and their neighbors)
  const candidates = new Set<string>();

  // Add all live cells
  for (const [x, y] of liveCells) {
    candidates.add(`${x},${y}`);
  }

  // Add all neighbors of live cells
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        candidates.add(`${x + dx},${y + dy}`);
      }
    }
  }

  const nextGen: Array<[number, number]> = [];

  // Check each candidate cell
  for (const key of candidates) {
    const [x, y] = key.split(",").map(Number);
    const isAlive = liveCells.some(([cx, cy]) => cx === x && cy === y);
    const neighbors = countNeighbors(x, y);

    // Survival rule: live cell with 2 or 3 neighbors
    if (isAlive && (neighbors === 2 || neighbors === 3)) {
      nextGen.push([x, y]);
    }
    // Reproduction rule: dead cell with exactly 3 neighbors
    else if (!isAlive && neighbors === 3) {
      nextGen.push([x, y]);
    }
  }

  return nextGen;
}

